    const entry = filteredHistory[selectedIndex];
    if (!entry) return;
    setActionsOpen(false);
    performCopy(entry.translatedText, showHUD, {
      hudIcon: <TranslateHUDIcon />,
      hudTitle: 'Translation Copied',
    });
