            </div>
          </div>
        </div>
      </div>
      <ActionPanel
        contextLabel="Translate"
        actions={[
          {
            label: 'Copy Translation',
            shortcut: (
              <Kbd
                keys={[
                  '\u2318',
                  'C',
                ]}
              />
            ),
          },
          {
            label: 'Actions',
            shortcut: (
              <Kbd
                keys={[
                  '\u2318',
                  'K',
                ]}
              />
            ),
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={translateDropdownSections}
        onDropdownClose={closeActions}
      />
      <HUDContainer items={hudItems} />
    </>
  );
}

